let raw = $.steps.aiExtract.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { primaryKeyword: raw.slice(0, 100), secondaryKeywords: [], recommendations: [] }; }

const ai = $.steps.parseAI.output;
const query = (ai.primaryKeyword || '') + ' ' + (ai.secondaryKeywords || []).slice(0, 2).join(' ');
return { query };

const ai = $.steps.parseAI.output;
const competitors = ($.steps.researchCompetition.response.results || []).map(r => r.url).join(', ');
const date = new Date().toISOString().split('T')[0];

const rows = [];
rows.push([date, $.input.targetUrl, ai.primaryKeyword || '', 'primary', ai.topicCluster || '', ai.contentType || '', competitors]);
(ai.secondaryKeywords || []).forEach(kw => {
  rows.push([date, $.input.targetUrl, kw, 'secondary', ai.topicCluster || '', ai.contentType || '', '']);
});
(ai.longTailKeywords || []).forEach(kw => {
  rows.push([date, $.input.targetUrl, kw, 'long-tail', ai.topicCluster || '', ai.contentType || '', '']);
});

return { rows, keywordCount: rows.length, summary: 'Extracted ' + rows.length + ' keywords from ' + $.input.targetUrl + '. Primary: ' + (ai.primaryKeyword || 'N/A') };
